{"content": "     1|"use client"
     2|import { createContext, useContext, useState, useEffect, ReactNode } from "react"
     3|import { STORAGE_KEYS } from "@ai-whisperers/auth/storage-keys"
     4|import es from "@/content/es.json"
     5|
     6|type Currency = "PYG" | "USD"
     7|// Rate from content config, fallback to 7400
     8|const RATE_PYG_PER_USD = (es as any)?.paymentGateway?.rate || 7400
     9|
    10|interface CurrencyCtx {
    11|  currency: Currency
    12|  setCurrency: (c: Currency) => void
    13|  formatPrice: (pygStr: string) => string
    14|  formatDual: (pygStr: string) => { pyg: string; usd: string }
    15|}
    16|
    17|const CurrencyContext = createContext<CurrencyCtx>(null!)
    18|
    19|export function CurrencyProvider({ children }: { children: ReactNode }) {
    20|  const [currency, setCur] = useState<Currency>("PYG")
    21|
    22|  useEffect(() => {
    23|    const saved = localStorage.getItem(STORAGE_KEYS.CURRENCY) as Currency | null
    24|    if (saved === "PYG" || saved === "USD") setCur(saved)
    25|  }, [])
    26|
    27|  const setCurrency = (c: Currency) => {
    28|    setCur(c)
    29|    localStorage.setItem(STORAGE_KEYS.CURRENCY, c)
    30|  }
    31|
    32|  const pygNum = (pygStr: string): number => {
    33|    const m = pygStr.match(/[\d.,]+/)
    34|    return m ? parseFloat(m[0].replace(/\./g, "").replace(",", ".")) : 0
    35|  }
    36|
    37|  const formatPrice = (pygStr: string): string => {
    38|    const n = pygNum(pygStr)
    39|    if (currency === "USD") {
    40|      const usd = n / RATE_PYG_PER_USD
    41|      return `USD ${usd.toFixed(2)}`
    42|    }
    43|    return pygStr
    44|  }
    45|
    46|  const formatDual = (pygStr: string) => {
    47|    const n = pygNum(pygStr)
    48|    return {
    49|      pyg: `Gs. ${n.toLocaleString("es-PY")}`,
    50|      usd: `USD ${(n / RATE_PYG_PER_USD).toFixed(2)}`,
    51|    }
    52|  }
    53|
    54|  return (
    55|    <CurrencyContext.Provider value={{ currency, setCurrency, formatPrice, formatDual }}>
    56|      {children}
    57|    </CurrencyContext.Provider>
    58|  )
    59|}
    60|
    61|export function useCurrency() {
    62|  const ctx = useContext(CurrencyContext)
    63|  if (!ctx) throw new Error("useCurrency must be used within CurrencyProvider")
    64|  return ctx
    65|}
